CREATE OR REPLACE FUNCTION project.chantier_create(p_row project.project)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  p_row.tenant_id := current_setting('app.tenant_id', true);
  p_row.numero := project._next_numero();
  p_row.statut := COALESCE(NULLIF(p_row.statut, ''), 'preparation');
  p_row.created_at := now();
  p_row.updated_at := now();

  INSERT INTO project.chantier (numero, client_id, devis_id, objet, adresse, statut,
    date_debut, date_fin_prevue, notes, created_at, updated_at, tenant_id)
  VALUES (p_row.numero, p_row.client_id, p_row.devis_id, p_row.objet, p_row.adresse, p_row.statut,
    p_row.date_debut, p_row.date_fin_prevue, p_row.notes, p_row.created_at, p_row.updated_at, p_row.tenant_id)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_create(project.project) IS 'Create chantier — auto-generates numero, sets tenant_id and timestamps';

CREATE OR REPLACE FUNCTION project.chantier_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  DELETE FROM project.chantier
  WHERE id = p_id::int AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_delete(text) IS 'Delete chantier by id — returns deleted row as jsonb or NULL';

CREATE OR REPLACE FUNCTION project.chantier_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(c) || jsonb_build_object(
        'client_name', cl.name,
        'devis_numero', d.numero,
        'avancement', project._avancement_global(c.id)
      )
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
      WHERE c.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY c.updated_at DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(c) || jsonb_build_object(
        ''client_name'', cl.name,
        ''devis_numero'', d.numero,
        ''avancement'', project._avancement_global(c.id)
      )
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
      WHERE c.tenant_id = ' || quote_literal(current_setting('app.tenant_id', true))
      || ' AND ' || pgv.rsql_to_where(p_filter, 'project', 'chantier')
      || ' ORDER BY c.updated_at DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION project.chantier_list(text) IS 'List chantiers for current tenant with client name and devis numero resolved — optional RSQL filter';

CREATE OR REPLACE FUNCTION project.chantier_options(p_search text DEFAULT ''::text)
 RETURNS TABLE(value text, label text, detail text)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
    SELECT c.id::text,
           c.numero || ' — ' || pgv.esc(c.objet),
           project._statut_badge(c.statut)
      FROM project.chantier c
     WHERE p_search = ''
        OR c.numero ILIKE '%' || p_search || '%'
        OR c.objet  ILIKE '%' || p_search || '%'
     ORDER BY c.updated_at DESC NULLS LAST
     LIMIT 20;
END;
$function$;
COMMENT ON FUNCTION project.chantier_options(text) IS 'Recherche chantiers pour pgv.select_search() — retourne value/label/detail';

CREATE OR REPLACE FUNCTION project.chantier_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_row jsonb;
  v_statut text;
  v_actions jsonb := '[]'::jsonb;
  v_uri text;
BEGIN
  SELECT to_jsonb(c) || jsonb_build_object(
    'client_name', cl.name,
    'devis_numero', d.numero,
    'avancement', project._avancement_global(c.id),
    'heures_total', (SELECT COALESCE(sum(heures), 0) FROM project.pointage WHERE chantier_id = c.id),
    'jalons_count', (SELECT count(*) FROM project.jalon WHERE chantier_id = c.id)
  ) INTO v_row
  FROM project.chantier c
  JOIN crm.client cl ON cl.id = c.client_id
  LEFT JOIN quote.devis d ON d.id = c.devis_id
  WHERE c.id = p_id::int AND c.tenant_id = current_setting('app.tenant_id', true);

  IF v_row IS NULL THEN RETURN NULL; END IF;

  v_statut := v_row ->> 'statut';
  v_uri := 'project://chantier/' || p_id;

  CASE v_statut
    WHEN 'preparation' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'demarrer', 'uri', v_uri || '/demarrer'),
        jsonb_build_object('method', 'edit', 'uri', v_uri),
        jsonb_build_object('method', 'supprimer', 'uri', v_uri || '/supprimer')
      );
    WHEN 'execution' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'reception', 'uri', v_uri || '/reception'),
        jsonb_build_object('method', 'edit', 'uri', v_uri)
      );
    WHEN 'reception' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'clore', 'uri', v_uri || '/clore')
      );
    ELSE
      v_actions := '[]'::jsonb;
  END CASE;

  v_row := v_row || jsonb_build_object('actions', v_actions);
  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION project.chantier_read(text) IS 'Read chantier by id — returns enriched jsonb with client name and devis numero';

CREATE OR REPLACE FUNCTION project.chantier_update(p_row project.project)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  UPDATE project.chantier SET
    client_id = COALESCE(p_row.client_id, client_id),
    devis_id = COALESCE(p_row.devis_id, devis_id),
    objet = COALESCE(NULLIF(p_row.objet, ''), objet),
    adresse = COALESCE(p_row.adresse, adresse),
    date_debut = COALESCE(p_row.date_debut, date_debut),
    date_fin_prevue = COALESCE(p_row.date_fin_prevue, date_fin_prevue),
    notes = COALESCE(p_row.notes, notes),
    updated_at = now()
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_update(project.project) IS 'Partial update chantier by id — COALESCE preserves unset fields';

CREATE OR REPLACE FUNCTION project.chantier_view()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_object(
    'uri', 'project://chantier',
    'icon', '◎',
    'label', 'project.entity_chantier',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
